import './Tabbar.scss';

import { Divider } from ':components/Divider';
import { classNames } from ':helpers/classnames';
import React, { isValidElement } from 'react';

import type { TabbarProps } from './Tabbar.types';
import type { TabbarItemProps } from './TabbarItem';
import { TabbarItem } from './TabbarItem';

export const Tabbar: React.FC<TabbarProps> = ({ className, type = 'default', children, ...rest }) => {
	const provideTypeProp = element =>
		isValidElement<TabbarItemProps>(element) && element.type === TabbarItem
			? React.cloneElement(element, { type })
			: element;
	return (
		<nav data-testid="Tabbar" className={classNames('dsb_tabbar', `dsb_tabbar-${type}`, className)} {...rest}>
			<ul className="dsb_tabbar__items">
				{Array.isArray(children) ? children.map(child => provideTypeProp(child)) : provideTypeProp(children)}
			</ul>
		</nav>
	);
};
